export const DEMOS_LIST_HTML = "\n\n\n\n<header class=\"dm-hero\">\n  <div class=\"dm-hero__inner\">\n    <div class=\"dm-breadcrumb\">\n      <a href=\"/\">Evalia</a><span class=\"sep\">\u203a</span><span>Demos</span>\n    </div>\n    <h1 class=\"dm-h1\">Ejemplos reales sobre documentos del <em>SEIA</em>.</h1>\n    <div class=\"dm-hero__meta\">\n      <span>Disponibles <strong>2</strong></span>\n    </div>\n  </div>\n</header>\n\n<!-- Selector de herramienta -->\n<div class=\"dm-filter-bar\">\n  <div class=\"dm-filter\" role=\"tablist\" aria-label=\"Filtrar por herramienta\">\n    <span class=\"dm-filter__label\">Ver por herramienta</span>\n    <button class=\"dm-chip is-on\" data-tool=\"all\" role=\"tab\" aria-selected=\"true\">\n      <span class=\"dm-chip__kind\">Todas</span>\n      <span class=\"dm-chip__name\">Ver las 2 demos</span>\n    </button>\n    <button class=\"dm-chip\" data-tool=\"consistencia\" role=\"tab\" aria-selected=\"false\">\n      <span class=\"dm-chip__kind\">Herramienta</span>\n      <span class=\"dm-chip__name\">An\u00e1lisis de consistencia de documentos</span>\n    </button>\n  </div>\n</div>\n\n<section class=\"dm-wrap\">\n  <div class=\"dm-wrap__inner\">\n\n    <div class=\"dm-head\">\n      <h2 id=\"grid-heading\">Demos disponibles</h2>\n      <div class=\"count\"><span id=\"grid-count\">2</span> demo<span id=\"grid-plural\">s</span></div>\n    </div>\n\n    <div class=\"dm-grid\" id=\"dm-grid\">\n\n      <a class=\"dm-card\" data-tool=\"consistencia\" href=\"/demos/thayari-consistencia\">\n        <div class=\"dm-card__tool\">An\u00e1lisis de consistencia de documentos</div>\n        <h3 class=\"dm-card__demo\">An\u00e1lisis de consistencia</h3>\n        <div class=\"dm-card__project\">Parque E\u00f3lico y Solar Thayari</div>\n        <div class=\"dm-card__scope\">EIA \u00b7 Descripci\u00f3n de Proyecto</div>\n        <p class=\"dm-card__desc\">Detecta contradicciones num\u00e9ricas, referencias rotas, compromisos sin respaldo y discrepancias entre versiones. Salida priorizada por severidad.</p>\n        <div class=\"dm-card__cta\"><span>Abrir demo</span><span class=\"arr\">\u2192</span></div>\n      </a>\n\n      <a class=\"dm-card\" data-tool=\"consistencia\" href=\"/demos/el-abra-consistencia\">\n        <div class=\"dm-card__tool\">An\u00e1lisis de consistencia de documentos</div>\n        <h3 class=\"dm-card__demo\">An\u00e1lisis de consistencia</h3>\n        <div class=\"dm-card__project\">Continuidad Operacional Minera El Abra</div>\n        <div class=\"dm-card__scope\">EIA \u00b7 Descripci\u00f3n de Proyecto</div>\n        <p class=\"dm-card__desc\">Detecta contradicciones num\u00e9ricas, referencias rotas, compromisos sin respaldo y discrepancias entre versiones. Salida priorizada por severidad.</p>\n        <div class=\"dm-card__cta\"><span>Abrir demo</span><span class=\"arr\">\u2192</span></div>\n      </a>\n\n      <div class=\"dm-empty\" id=\"dm-empty\">No hay demos disponibles para esta herramienta. Pr\u00f3ximamente.</div>\n\n    </div>\n\n    <div class=\"dm-note\">\n      <strong>Nota.</strong> Cada demo es navegable pero no editable desde la landing. Para ver una herramienta aplicada a documentos propios, el formato sugerido es un piloto acotado. Escr\u00edbanos a <a href=\"mailto:evalia@inventures.cl\" style=\"color:var(--ev-accent)\">evalia@inventures.cl</a>.\n    </div>\n\n  </div>\n</section>\n\n\n\n\n\n<!-- @bundle-js: js/nav.js js/landing.js -->\n<!-- @end-bundle -->\n";

export const DEMOS_LIST_JS = "\n/* === js/nav.js === */\n/* ============================================================\n   EVALIA \u00b7 NAV + FOOTER UNIVERSAL\n   Inyecta la misma barra superior y footer en cada p\u00e1gina.\n   - En p\u00e1ginas ra\u00edz (index/an\u00e1lisis/caso/demos)  \u2192 base = ./\n   - En p\u00e1ginas dentro de subcarpeta (analisis/ o demos/) \u2192 base = ../\n   ============================================================ */\n(() => {\n  'use strict';\n\n  // \u2500\u2500 base path \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  const parts = location.pathname.split('/').filter(Boolean);\n  const isSub = parts.length >= 2 && /^(analisis|demos)$/i.test(parts[parts.length - 2]);\n  const base = isSub ? '../' : './';\n\n  // \u2500\u2500 current tab \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  function detectCurrent() {\n    const p = location.pathname;\n    if (/\\/demos\\.html/i.test(p)) return 'demos';\n    if (/\\/demos\\//i.test(p)) return 'demos';\n    if (/\\/analisis(\\.html|\\/)/i.test(p)) return 'analisis';\n    return 'inicio';\n  }\n\n  // \u2500\u2500 HTML \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  function navHTML(current) {\n    const on = (k) => current === k ? ' class=\"is-current\"' : '';\n    const trigOn = current === 'analisis' ? ' is-current' : '';\n    return `\n      <div class=\"ev-site-nav__left\">\n        <a href=\"${base}index.html\" aria-label=\"Evalia \u2014 Inicio\" class=\"ev-nav-brand\">\n          <img src=\"${base}assets/evalia-logo-white.svg\" alt=\"Evalia\" class=\"ev-nav-brand__logo\" />\n          <span class=\"ev-nav-brand__by\">por Inventures</span>\n        </a>\n      </div>\n      <div class=\"ev-site-nav__right\">\n        <div class=\"nav-group\">\n          <a href=\"${base}index.html#que-es\"${on('inicio')}>Qu\u00e9 es</a>\n          <a href=\"${base}index.html#como-funciona\">C\u00f3mo funciona</a>\n          <a href=\"${base}index.html#evaluacion-ambiental\">Evaluaci\u00f3n ambiental</a>\n          <a href=\"${base}demos.html\"${on('demos')}>Demos</a>\n          <a href=\"${base}index.html#seguridad\">Seguridad</a>\n          <a href=\"${base}index.html#qa\">Preguntas</a>\n        </div>\n        <span class=\"nav-divider\"></span>\n        <div class=\"nav-dropdown\">\n          <button type=\"button\" class=\"nav-dropdown__trigger${trigOn}\" aria-haspopup=\"true\" aria-expanded=\"false\">Estudios<span class=\"nav-dropdown__chevron\" aria-hidden=\"true\">\u25be</span></button>\n          <div class=\"nav-dropdown__menu\" role=\"menu\">\n            <a href=\"${base}analisis.html\" class=\"nav-dropdown__head\" role=\"menuitem\">Ver todos los estudios <span class=\"arr\">\u2192</span></a>\n            <a href=\"${base}analisis/antofagasta-carga.html\" role=\"menuitem\">Carga documental \u00b7 Antofagasta</a>\n            <a href=\"${base}analisis/etapas-seia.html\" role=\"menuitem\">Tiempos por etapa SEIA</a>\n            <a href=\"${base}analisis/responsables-estatales.html\" role=\"menuitem\">Responsables estatales</a>\n            <a href=\"${base}analisis/organizaciones.html\" role=\"menuitem\">Ranking por organismo</a>\n          </div>\n        </div>\n        <a href=\"${base}index.html#proximos\" class=\"cta\">Agendar demo</a>\n      </div>`;\n  }\n\n  function footerHTML() {\n    return `\n      <div class=\"ev-site-footer__left\">\n        <div class=\"ev-footer__brand\">\n          <img src=\"${base}assets/evalia-logo-white.svg\" alt=\"Evalia\" class=\"ev-footer__logo\" />\n          <span class=\"ev-footer__by\">por Inventures</span>\n        </div>\n        <div class=\"ev-footer__tag\">IA aplicada al ciclo EIA/DIA. Evalia es una operaci\u00f3n interna de Inventures: consultor\u00eda y tecnolog\u00eda para los proyectos de inversi\u00f3n que el pa\u00eds necesita sacar adelante.</div>\n      </div>\n      <div class=\"ev-site-footer__mid\">\n        <div class=\"ev-footer__eyebrow\">Producto de</div>\n        <a href=\"https://inventures.cl\" target=\"_blank\" rel=\"noopener\" class=\"ev-footer__inv-name\">Inventures <span class=\"ev-footer__external-note\">inventures.cl \u2197</span></a>\n      </div>\n      <div class=\"ev-site-footer__right\">\n        <div class=\"ev-footer__eyebrow\">Contacto</div>\n        <a href=\"mailto:evalia@inventures.cl\" class=\"ev-footer__mail\">evalia@inventures.cl</a>\n        <div class=\"ev-footer__loc\">Santiago \u00b7 Chile \u00b7 2026</div>\n      </div>`;\n  }\n\n  // \u2500\u2500 mount \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  function mount() {\n    const current = detectCurrent();\n\n    // NAV\n    let nav = document.querySelector('nav.ev-site-nav');\n    if (!nav) {\n      nav = document.createElement('nav');\n      nav.className = 'ev-site-nav';\n      document.body.insertBefore(nav, document.body.firstChild);\n    }\n    nav.id = 'site-nav';\n    nav.innerHTML = navHTML(current);\n\n    // FOOTER \u2014 s\u00f3lo si ya existe un <footer.ev-site-footer> lo sobreescribimos\n    const f = document.querySelector('footer.ev-site-footer');\n    if (f) {\n      f.innerHTML = footerHTML();\n    }\n\n    // Nav solid-on-scroll (replica el comportamiento de landing.js para\n    // que las p\u00e1ginas que no cargan landing.js \u2014 como las demos \u2014 tambi\u00e9n\n    // tengan nav blanco al hacer scroll).\n    if (!window.__evNavScrollBound) {\n      window.__evNavScrollBound = true;\n      const onScroll = () => nav.classList.toggle('is-solid', window.scrollY > 60);\n      window.addEventListener('scroll', onScroll, { passive: true });\n      onScroll();\n    }\n  }\n\n  if (document.readyState === 'loading') {\n    document.addEventListener('DOMContentLoaded', mount);\n  } else {\n    mount();\n  }\n})();\n\n\n/* === js/landing.js === */\n/* ============================================================\n   EVALIA \u00b7 LANDING JS\n   - Nav solida al scrollear\n   - Reveal on scroll (IntersectionObserver)\n   - Panel de tweaks (dev) sincronizado entre p\u00e1ginas via localStorage\n   ============================================================ */\n\n(() => {\n  'use strict';\n\n  const LS_KEY = 'evalia.tweaks.v1';\n\n  // Valores por defecto. Editables a mano por el equipo desde el HTML.\n  const TWEAK_DEFAULTS = /*EDITMODE-BEGIN*/{\n    accent: 'green'\n  }/*EDITMODE-END*/;\n\n  // Lee tweaks persistidos de localStorage (si existen) y los mergea.\n  function readState() {\n    try {\n      const raw = localStorage.getItem(LS_KEY);\n      if (!raw) return { ...TWEAK_DEFAULTS };\n      const parsed = JSON.parse(raw);\n      return { ...TWEAK_DEFAULTS, ...parsed };\n    } catch (_) {\n      return { ...TWEAK_DEFAULTS };\n    }\n  }\n  function writeState(s) {\n    try { localStorage.setItem(LS_KEY, JSON.stringify(s)); } catch (_) {}\n  }\n\n  const state = readState();\n\n  function applyAccent(accent) {\n    if (!accent) return;\n    document.body.dataset.accent = accent;\n  }\n\n  // Aplicar el accent global antes de cualquier otra cosa para evitar flash.\n  applyAccent(state.accent);\n\n  /* \u2500\u2500 Nav: fondo s\u00f3lido al scrollear \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  const nav = document.getElementById('site-nav');\n  if (nav) {\n    const onScroll = () => nav.classList.toggle('is-solid', window.scrollY > 60);\n    window.addEventListener('scroll', onScroll, { passive: true });\n    onScroll();\n  }\n\n  /* \u2500\u2500 Reveal on scroll \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  const revealEls = document.querySelectorAll('.ev-reveal');\n  if (revealEls.length) {\n    const io = new IntersectionObserver((entries) => {\n      entries.forEach((e) => {\n        if (e.isIntersecting) {\n          e.target.classList.add('is-visible');\n          io.unobserve(e.target);\n        }\n      });\n    }, { threshold: 0.08, rootMargin: '0px 0px -60px 0px' });\n    revealEls.forEach((el) => io.observe(el));\n  }\n\n  /* \u2500\u2500 Sincronizaci\u00f3n entre pesta\u00f1as via storage event \u2500\u2500 */\n  window.addEventListener('storage', (ev) => {\n    if (ev.key !== LS_KEY) return;\n    try {\n      const next = JSON.parse(ev.newValue || '{}');\n      if (next.accent) { state.accent = next.accent; applyAccent(state.accent); paintPanel(); }\n    } catch (_) {}\n  });\n\n  /* \u2500\u2500 Panel de tweaks (dev) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  const panel = document.getElementById('tweaks-panel');\n  if (!panel) {\n    // La p\u00e1gina no monta panel (ej. detalle de an\u00e1lisis), pero igual persistimos\n    // el estilo desde localStorage, que ya est\u00e1 aplicado arriba.\n    try { window.parent.postMessage({ type: '__edit_mode_available' }, '*'); } catch (_) {}\n    return;\n  }\n\n  function paintPanel() {\n    panel.querySelectorAll('.ev-tweaks__seg').forEach((seg) => {\n      const key = seg.dataset.group;\n      seg.querySelectorAll('button').forEach((b) => {\n        b.classList.toggle('is-on', b.dataset.val === state[key]);\n      });\n    });\n  }\n  paintPanel();\n\n  panel.querySelectorAll('.ev-tweaks__seg').forEach((seg) => {\n    seg.addEventListener('click', (ev) => {\n      const btn = ev.target.closest('button[data-val]');\n      if (!btn) return;\n      const key = seg.dataset.group;\n      state[key] = btn.dataset.val;\n      if (key === 'accent') applyAccent(state.accent);\n      paintPanel();\n      writeState(state);\n      try {\n        window.parent.postMessage(\n          { type: '__edit_mode_set_keys', edits: { [key]: btn.dataset.val } },\n          '*'\n        );\n      } catch (_) {}\n    });\n  });\n\n  window.addEventListener('message', (ev) => {\n    const d = ev.data || {};\n    if (d.type === '__activate_edit_mode') panel.classList.add('is-on');\n    else if (d.type === '__deactivate_edit_mode') panel.classList.remove('is-on');\n  });\n\n  try { window.parent.postMessage({ type: '__edit_mode_available' }, '*'); } catch (_) {}\n})();\n\n/* ============================================================\n   FLUJO HERRAMIENTAS \u00b7 Interacci\u00f3n rail \u2194 detalle\n   ============================================================ */\n(() => {\n  'use strict';\n\n  const rail = document.querySelector('.ev-flow__rail');\n  const detail = document.getElementById('flow-detail');\n  const dataEl = document.getElementById('ev-tools-data');\n  if (!rail || !detail || !dataEl) return;\n\n  let data;\n  try { data = JSON.parse(dataEl.textContent); } catch (_) { return; }\n  const { tools, phases } = data;\n\n  const esc = (s) => String(s).replace(/[&<>\"']/g, (c) => ({'&':'&amp;','<':'&lt;','>':'&gt;','\"':'&quot;',\"'\":'&#39;'}[c]));\n\n  function render(phaseId) {\n    const phaseName = phases[phaseId] || '';\n    const btn = rail.querySelector(`[data-phase=\"${phaseId}\"]`);\n    const ids = (btn?.dataset.tools || '').split(',').filter(Boolean);\n\n    let html = '';\n    if (ids.length === 0) {\n      html = `\n        <div class=\"ev-flow__soon\">\n          <div>\n            <h4>En construcci\u00f3n <em>\u00b7 pr\u00f3xima ventana de producto.</em></h4>\n            <p>Estamos evaluando qu\u00e9 parte de esta etapa es mec\u00e1nica, qu\u00e9 parte es criterio t\u00e9cnico del cliente y d\u00f3nde un agente puede aportar sin erosionar la decisi\u00f3n experta. Si tienes un dolor concreto en esta etapa, escr\u00edbenos para ayudarnos a priorizar: <a href=\"mailto:evalia@inventures.cl?subject=Fase%20${encodeURIComponent(phaseName)}\">cont\u00e1ctanos</a>.</p>\n          </div>\n          <div class=\"ev-flow__soon-badge\">Pr\u00f3ximamente</div>\n        </div>`;\n    } else {\n      const cards = ids.map((k) => {\n        const t = tools[k];\n        if (!t) return '';\n        return `\n          <article class=\"ev-tool-card\" data-tool-open=\"${esc(t.id)}\" tabindex=\"0\" role=\"button\" aria-label=\"Ver detalle de ${esc(t.name)}\">\n            <h3 class=\"ev-tool-card__title\">${esc(t.name)}</h3>\n            <p class=\"ev-tool-card__body\">${t.short || t.body}</p>\n            <div class=\"ev-tool-card__cta\">Ver detalle <span class=\"arr\">\u2192</span></div>\n          </article>`;\n      }).join('');\n      html = `<div class=\"ev-flow__tools-grid\">${cards}</div>`;\n    }\n\n    detail.classList.add('is-fading');\n    setTimeout(() => {\n      detail.innerHTML = html;\n      detail.classList.remove('is-fading');\n    }, 120);\n  }\n\n  rail.addEventListener('click', (ev) => {\n    const btn = ev.target.closest('.ev-flow__phase');\n    if (!btn) return;\n    rail.querySelectorAll('.ev-flow__phase').forEach((b) => {\n      b.classList.toggle('is-active', b === btn);\n      b.setAttribute('aria-selected', b === btn ? 'true' : 'false');\n    });\n    render(btn.dataset.phase);\n  });\n\n  rail.addEventListener('keydown', (ev) => {\n    const btn = ev.target.closest('.ev-flow__phase');\n    if (!btn) return;\n    const all = [...rail.querySelectorAll('.ev-flow__phase')];\n    const idx = all.indexOf(btn);\n    if (ev.key === 'ArrowRight' || ev.key === 'ArrowLeft') {\n      ev.preventDefault();\n      const next = ev.key === 'ArrowRight' ? (idx + 1) % all.length : (idx - 1 + all.length) % all.length;\n      all[next].focus();\n      all[next].click();\n    }\n  });\n\n  // Render inicial: la fase marcada como is-active (Adenda por default)\n  const initial = rail.querySelector('.ev-flow__phase.is-active') || rail.querySelector('.ev-flow__phase');\n  if (initial) render(initial.dataset.phase);\n\n  /* \u2500\u2500 Modal de detalle de herramienta \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  const modal = document.getElementById('tool-modal');\n  if (!modal) return;\n  const titleEl = document.getElementById('tool-modal-title');\n  const bodyEl = document.getElementById('tool-modal-body');\n  const usesEl = document.getElementById('tool-modal-uses');\n  const noteEl = document.getElementById('tool-modal-note');\n\n  function openModal(toolId){\n    const t = tools[toolId];\n    if (!t) return;\n    titleEl.textContent = t.name;\n    bodyEl.innerHTML = t.body;\n    usesEl.innerHTML = (t.uses || []).map(u => `<li>${esc(u)}</li>`).join('');\n    noteEl.textContent = t.note || '';\n    modal.classList.add('is-open');\n    modal.setAttribute('aria-hidden', 'false');\n    document.body.style.overflow = 'hidden';\n  }\n  function closeModal(){\n    modal.classList.remove('is-open');\n    modal.setAttribute('aria-hidden', 'true');\n    document.body.style.overflow = '';\n  }\n\n  detail.addEventListener('click', (ev) => {\n    const card = ev.target.closest('[data-tool-open]');\n    if (!card) return;\n    openModal(card.dataset.toolOpen);\n  });\n  detail.addEventListener('keydown', (ev) => {\n    const card = ev.target.closest('[data-tool-open]');\n    if (!card) return;\n    if (ev.key === 'Enter' || ev.key === ' ') {\n      ev.preventDefault();\n      openModal(card.dataset.toolOpen);\n    }\n  });\n  modal.addEventListener('click', (ev) => {\n    if (ev.target.closest('[data-close]')) closeModal();\n  });\n  document.addEventListener('keydown', (ev) => {\n    if (ev.key === 'Escape' && modal.classList.contains('is-open')) closeModal();\n  });\n})();\n\n";

export const DEMOS_LIST_CSS = "\n.ev-site-nav__right .nav-group{ display:flex; gap:28px; align-items:center; }\n.ev-site-nav__right .nav-divider{ width:1px; height:16px; background: currentColor; opacity:0.25; }\n.ev-site-nav__right a.is-current{ color: var(--ev-accent); }\n\n/* Hero sobrio \u2014 sin titular narrativo */\n.dm-hero{ background: var(--ev-navy-900); color:#fff; padding: 120px 48px 56px; position:relative; overflow:hidden; isolation:isolate; }\n.dm-hero::before{ content:''; position:absolute; inset:0; background:\n  radial-gradient(ellipse 60% 60% at 15% 25%, rgba(0,198,223,0.12), transparent 60%); z-index:-1; }\n.dm-hero__inner{ max-width:1360px; margin:0 auto; }\n.dm-breadcrumb{ font-family: var(--ev-font-mono); font-size:11px; letter-spacing:2.5px; text-transform:uppercase; color: rgba(255,255,255,0.55); margin-bottom: 18px; font-weight:500; }\n.dm-breadcrumb a{ color: rgba(255,255,255,0.55); text-decoration:none; }\n.dm-breadcrumb a:hover{ color: var(--ev-accent); }\n.dm-breadcrumb .sep{ margin: 0 10px; opacity: 0.5; }\n.dm-h1{ font-size: var(--ev-fs-page-title); font-weight:300; line-height: var(--ev-lh-page-title); letter-spacing: var(--ev-ls-page-title); color:#fff; max-width: 1000px; margin: 0; text-wrap: balance; }\n.dm-h1 em{ font-style:normal; color: var(--ev-accent); font-weight:400; }\n.dm-hero__meta{ margin-top: 28px; display:flex; gap: 32px; font-family: var(--ev-font-mono); font-size:11px; letter-spacing:2px; text-transform:uppercase; color: rgba(255,255,255,0.6); }\n.dm-hero__meta strong{ color:#fff; font-weight:500; margin-left: 10px; }\n\n/* Selector de herramienta */\n.dm-filter-bar{\n  background: var(--ev-navy-900); color:#fff;\n  padding: 0 48px 48px;\n  border-bottom: 1px solid rgba(255,255,255,0.08);\n}\n.dm-filter{\n  max-width: 1360px; margin: 0 auto;\n  display:flex; gap: 14px; align-items:stretch;\n  flex-wrap: wrap;\n}\n.dm-filter__label{\n  font-family: var(--ev-font-mono); font-size:10.5px; letter-spacing:2.5px;\n  text-transform: uppercase; color: rgba(255,255,255,0.55); font-weight:500;\n  align-self: center; margin-right: 8px;\n}\n.dm-chip{\n  background: rgba(255,255,255,0.04);\n  border: 1px solid rgba(255,255,255,0.12);\n  color: rgba(255,255,255,0.72);\n  padding: 12px 20px 14px; border-radius: 3px;\n  font-family: var(--ev-font-body);\n  font-size: 13.5px; font-weight: 400; letter-spacing: -0.01em;\n  cursor: pointer; transition: all 0.2s ease;\n  display: flex; flex-direction: column; gap: 3px; min-width: 180px;\n  text-align: left;\n}\n.dm-chip__kind{\n  font-family: var(--ev-font-mono); font-size: 10px; letter-spacing: 2px;\n  text-transform: uppercase; color: rgba(255,255,255,0.45); font-weight: 500;\n}\n.dm-chip__name{ color: rgba(255,255,255,0.9); font-weight: 400; }\n.dm-chip:hover{ border-color: var(--ev-accent); color:#fff; background: rgba(0,198,223,0.05); }\n.dm-chip.is-on{\n  background: var(--ev-accent); color: var(--ev-navy-900);\n  border-color: var(--ev-accent);\n}\n.dm-chip.is-on .dm-chip__kind{ color: rgba(0,33,50,0.65); }\n.dm-chip.is-on .dm-chip__name{ color: var(--ev-navy-900); font-weight:500; }\n.dm-chip__count{\n  font-family: var(--ev-font-mono); font-size: 10px; opacity: 0.6;\n  margin-left: auto; align-self: flex-start;\n}\n\n/* Grid */\n.dm-wrap{ padding: 64px 48px 120px; background: var(--ev-bg); }\n.dm-wrap__inner{ max-width: 1360px; margin: 0 auto; }\n.dm-head{ display:flex; justify-content:space-between; align-items:baseline; padding-bottom:28px; border-bottom: 1px solid var(--ev-line); margin-bottom: 40px; }\n.dm-head h2{ font-size:13px; font-family: var(--ev-font-mono); letter-spacing:3px; text-transform:uppercase; font-weight:500; color: var(--ev-navy-900); }\n.dm-head .count{ font-family: var(--ev-font-mono); font-size:11px; letter-spacing:2px; color: var(--ev-muted); }\n\n.dm-grid{ display:grid; grid-template-columns: repeat(2, 1fr); gap: 24px; }\n\n.dm-card{\n  background:#fff; border:1px solid var(--ev-line); border-radius:4px;\n  padding: 32px; text-decoration:none; color:inherit; display:flex; flex-direction:column;\n  position: relative; transition: all var(--ev-dur) var(--ev-ease);\n  min-height: 260px;\n}\n.dm-card.is-hidden{ display:none; }\n.dm-card:hover{ border-color: var(--ev-accent); transform: translateY(-3px); box-shadow: 0 20px 40px -20px rgba(0,0,0,0.12); }\n.dm-card::before{\n  content:''; position:absolute; top:0; left:0; right:0; height:3px;\n  background: var(--ev-accent); transform: scaleX(0); transform-origin:left;\n  transition: transform 0.4s var(--ev-ease);\n}\n.dm-card:hover::before{ transform: scaleX(1); }\n\n.dm-card__tool{\n  font-family: var(--ev-font-mono); font-size:10.5px; letter-spacing:2.5px; text-transform:uppercase;\n  color: var(--ev-accent); font-weight:500; margin-bottom: 14px;\n  display: inline-flex; align-items:center; gap:10px;\n}\n.dm-card__tool::before{ content:''; width:7px; height:7px; background: var(--ev-accent); border-radius:50%; }\n\n.dm-card__demo{\n  font-size: 24px; font-weight: 400; line-height: 1.25;\n  letter-spacing: -0.02em; color: var(--ev-navy-900);\n  margin-bottom: 14px;\n}\n\n.dm-card__project{\n  font-size: 13.5px; color: var(--ev-navy-900); font-weight:500;\n  margin-bottom: 6px; letter-spacing: -0.01em;\n}\n.dm-card__scope{\n  font-family: var(--ev-font-mono); font-size: 10.5px; letter-spacing: 1.5px;\n  color: var(--ev-muted); text-transform: uppercase; font-weight: 500;\n  margin-bottom: 18px;\n}\n\n.dm-card__desc{ font-size: 13px; line-height: 1.65; color: var(--ev-muted); font-weight:300; flex:1; }\n\n.dm-card__cta{\n  margin-top: 24px; padding-top: 20px; border-top: 1px solid var(--ev-line);\n  display:flex; justify-content: space-between; align-items:center;\n  font-size: 13px; color: var(--ev-navy-900); font-weight:500;\n}\n.dm-card__cta .arr{ transition: transform var(--ev-dur) var(--ev-ease); }\n.dm-card:hover .dm-card__cta .arr{ transform: translateX(6px); color: var(--ev-accent); }\n\n.dm-empty{\n  grid-column: 1 / -1;\n  padding: 64px 32px; text-align: center;\n  border: 1px dashed var(--ev-line); border-radius: 4px;\n  color: var(--ev-muted); font-size: 14px; font-weight: 300;\n  display: none;\n}\n.dm-empty.is-shown{ display:block; }\n\n.dm-note{\n  margin-top: 72px; padding: 28px 32px;\n  border-left: 3px solid var(--ev-accent); background: #FAFBFC;\n  font-size: 13.5px; color: var(--ev-navy-900); line-height: 1.7; font-weight: 300;\n  max-width: 820px;\n}\n.dm-note strong{ font-weight: 500; }\n\n@media (max-width: 900px){\n  .dm-hero{ padding: 100px 24px 40px; }\n  .dm-filter-bar{ padding: 0 24px 40px; }\n  .dm-wrap{ padding: 56px 24px 80px; }\n  .dm-grid{ grid-template-columns: 1fr; }\n  .dm-chip{ min-width: auto; flex: 1; }\n}\n";
